UPDATE public.questions SET
  stimulus_text = 'A scientist is writing about the process of photosynthesis. Which choice best completes the sentence so that it conforms to the conventions of Standard English?  The process of photosynthesis occurs in plants, algae, and some bacteria, which use sunlight to produce energy from carbon dioxide and water.  ______, the resulting energy is stored in the form of sugar, which the plant uses to grow.',
  question_text = 'Which transition best completes the sentence?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"Consequently. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"However. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"Moreover. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"Therefore. This choice completes the idea as a full sentence rather than a fragment.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The transition "Therefore" is the best choice because it shows a cause-and-effect relationship between the previous clause and the following clause. The previous clause explains the process of photosynthesis, and the following clause explains the resulting consequence of the process. The other transitions do not show this cause-and-effect relationship as well. "Consequently" suggests that the following clause is a result of the previous clause but does not emphasize the cause-and-effect relationship as clearly as "Therefore." "However" suggests a contrast between the previous clause and the following clause. "Moreover" adds additional information to the previous clause, but it does not indicate a cause-and-effect relationship. The passage states that "A scientist is writing about the process of photosynthesis. Which choice best completes the sentence so that it conforms…", which is the textual anchor for eliminating weaker choices. Choice D is correct because it aligns with that evidence: Therefore. This choice completes the idea as a full sentence rather than a fragment.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":974,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_c1","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.903Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
